import{_ as n,c as s,o as a,d as t}from"./app.86d6c556.js";const m='{"title":"Autenticaci\xF3n - Vue SPA","description":"","frontmatter":{},"headers":[{"level":2,"title":"Puntos finales de autenticaci\xF3n y CORS","slug":"puntos-finales-de-autenticacion-y-cors"},{"level":2,"title":"Sesiones, Cookies y CSRF","slug":"sesiones-cookies-y-csrf"},{"level":2,"title":"Protecci\xF3n de Rutas y Mantenimiento del Estado","slug":"proteccion-de-rutas-y-mantenimiento-del-estado"}],"relativePath":"vue/vue-authentication.md"}',o={},p=t(`<h1 id="autenticacion-vue-spa" tabindex="-1">Autenticaci\xF3n - Vue SPA <a class="header-anchor" href="#autenticacion-vue-spa" aria-hidden="true">#</a></h1><h2 id="puntos-finales-de-autenticacion-y-cors" tabindex="-1">Puntos finales de autenticaci\xF3n y CORS <a class="header-anchor" href="#puntos-finales-de-autenticacion-y-cors" aria-hidden="true">#</a></h2><p>Primero eche un vistazo al archivo <a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/services/index.ts" target="_blank" rel="noopener noreferrer">Servicios de Autenticaci\xF3n</a> para mantener todos los puntos finales de autenticaci\xF3n de API en un solo lugar. Los m\xE9todos en este archivo interact\xFAan con los puntos finales de Fortify que hemos configurado previamente.</p><div class="language-ts"><pre><code><span class="token comment">// modules/Auth/services/index.ts</span>
<span class="token keyword">import</span> Http <span class="token keyword">from</span> <span class="token string">&quot;@/utils/Http&quot;</span><span class="token punctuation">;</span>

<span class="token keyword">export</span> <span class="token keyword">const</span> login <span class="token operator">=</span> <span class="token generic-function"><span class="token function">async</span> <span class="token generic class-name"><span class="token operator">&lt;</span><span class="token constant">T</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span>payload<span class="token operator">:</span> <span class="token constant">T</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">await</span> Http<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&quot;/sanctum/csrf-cookie&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> Http<span class="token punctuation">.</span><span class="token function">post</span><span class="token punctuation">(</span><span class="token string">&quot;/login&quot;</span><span class="token punctuation">,</span> payload<span class="token punctuation">)</span><span class="token punctuation">;</span>
 <span class="token punctuation">}</span>

<span class="token keyword">export</span> <span class="token keyword">const</span> <span class="token function-variable function">logout</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> Http<span class="token punctuation">.</span><span class="token function">post</span><span class="token punctuation">(</span><span class="token string">&quot;/logout&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">export</span> <span class="token keyword">const</span> forgotPassword <span class="token operator">=</span> <span class="token generic-function"><span class="token function">async</span> <span class="token generic class-name"><span class="token operator">&lt;</span><span class="token constant">T</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span>payload<span class="token operator">:</span> <span class="token constant">T</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">await</span> Http<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&quot;/sanctum/csrf-cookie&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> Http<span class="token punctuation">.</span><span class="token function">post</span><span class="token punctuation">(</span><span class="token string">&quot;/forgot-password&quot;</span><span class="token punctuation">,</span> payload<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">export</span> <span class="token keyword">const</span> <span class="token function-variable function">getAuthUser</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> Http<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&quot;/api/users/auth&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">export</span> <span class="token keyword">const</span> resetPassword <span class="token operator">=</span> <span class="token generic-function"><span class="token function">async</span> <span class="token generic class-name"><span class="token operator">&lt;</span><span class="token constant">T</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span>payload<span class="token operator">:</span> <span class="token constant">T</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">await</span> Http<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&quot;/sanctum/csrf-cookie&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> Http<span class="token punctuation">.</span><span class="token function">post</span><span class="token punctuation">(</span><span class="token string">&quot;/reset-password&quot;</span><span class="token punctuation">,</span> payload<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">export</span> <span class="token keyword">const</span> updatePassword <span class="token operator">=</span> <span class="token operator">&lt;</span><span class="token constant">T</span><span class="token operator">&gt;</span><span class="token punctuation">(</span>payload<span class="token operator">:</span> <span class="token constant">T</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> Http<span class="token punctuation">.</span><span class="token function">put</span><span class="token punctuation">(</span><span class="token string">&quot;/user/password&quot;</span><span class="token punctuation">,</span> payload<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">export</span> <span class="token keyword">const</span> registerUser <span class="token operator">=</span> <span class="token generic-function"><span class="token function">async</span> <span class="token generic class-name"><span class="token operator">&lt;</span><span class="token constant">T</span><span class="token operator">&gt;</span></span></span><span class="token punctuation">(</span>payload<span class="token operator">:</span> <span class="token constant">T</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">await</span> Http<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&quot;/sanctum/csrf-cookie&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">return</span> Http<span class="token punctuation">.</span><span class="token function">post</span><span class="token punctuation">(</span><span class="token string">&quot;/register&quot;</span><span class="token punctuation">,</span> payload<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">export</span> <span class="token keyword">const</span> sendVerification <span class="token operator">=</span> <span class="token operator">&lt;</span><span class="token constant">T</span><span class="token operator">&gt;</span><span class="token punctuation">(</span>payload<span class="token operator">:</span> <span class="token constant">T</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> Http<span class="token punctuation">.</span><span class="token function">post</span><span class="token punctuation">(</span><span class="token string">&quot;/email/verification-notification&quot;</span><span class="token punctuation">,</span> payload<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">export</span> <span class="token keyword">const</span> updateUser <span class="token operator">=</span> <span class="token operator">&lt;</span><span class="token constant">T</span><span class="token operator">&gt;</span><span class="token punctuation">(</span>payload<span class="token operator">:</span> <span class="token constant">T</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> Http<span class="token punctuation">.</span><span class="token function">put</span><span class="token punctuation">(</span><span class="token string">&quot;/user/profile-information&quot;</span><span class="token punctuation">,</span> payload<span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>

<span class="token keyword">export</span> <span class="token keyword">const</span> <span class="token function-variable function">getAuthMenu</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">return</span> Http<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&quot;/api/users/auth-menu&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
<span class="token punctuation">}</span>
</code></pre></div><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Es importante resaltar que esto requiere que el SPA y la API compartan el mismo dominio de nivel superior. Sin embargo, pueden colocarse en diferentes subdominios.</p></div><h2 id="sesiones-cookies-y-csrf" tabindex="-1">Sesiones, Cookies y CSRF <a class="header-anchor" href="#sesiones-cookies-y-csrf" aria-hidden="true">#</a></h2><p>Para autenticar su SPA, la p\xE1gina de inicio de sesi\xF3n primero debe realizar una solicitud al extremo <code>/sanctum/csrf-cookie</code> para inicializar la protecci\xF3n CSRF para la aplicaci\xF3n:</p><div class="language-ts"><pre><code><span class="token keyword">await</span> Http<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&quot;/sanctum/csrf-cookie&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre></div><p>Esto tambi\xE9n se aplica a cualquier otra acci\xF3n de Fortify que requiera protecci\xF3n CSRF. Tenga en cuenta las otras rutas en el m\xF3dulo <code>AuthService</code> que tambi\xE9n incluyen una solicitud de obtenci\xF3n de la cookie CSRF; <code>forgotPassword</code>, <code>resetPassword</code>, etc.</p><p>Si una solicitud de inicio de sesi\xF3n tiene \xE9xito, el usuario se autentica y las solicitudes posteriores al SPA se autenticar\xE1n autom\xE1ticamente a trav\xE9s de la cookie de sesi\xF3n que emite la aplicaci\xF3n Laravel. Adem\xE1s, dado que ya hicimos una solicitud a la ruta <code>/sanctum/csrf-cookie</code>, las solicitudes posteriores deber\xEDan recibir autom\xE1ticamente protecci\xF3n CSRF porque Axios env\xEDa autom\xE1ticamente la cookie XSRF-TOKEN en el encabezado X-XSRF-TOKEN.</p><h2 id="proteccion-de-rutas-y-mantenimiento-del-estado" tabindex="-1">Protecci\xF3n de Rutas y Mantenimiento del Estado <a class="header-anchor" href="#proteccion-de-rutas-y-mantenimiento-del-estado" aria-hidden="true">#</a></h2><p>El m\xE9todo para proteger las rutas de su aplicaci\xF3n es bastante simple. En los archivos de rutas, como el caso del m\xF3dulo <code>Auth</code> hay un metacampo <a href="https://github.com/garethredfern/laravel-vue/blob/v1.2.7/src/router/index.js" target="_blank" rel="noopener noreferrer">requiresAuth</a>, es un valor booleano que se mantiene contra cada ruta que desea proteger. Usando el enrutador Vue antes de cada m\xE9todo, verifique si una ruta tiene un booleano <code>auth</code> de verdadero y si hay un usuario autenticado en el <a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/stores/index.ts" target="_blank" rel="noopener noreferrer">AuthStore</a>:</p><div class="language-ts"><pre><code>router<span class="token punctuation">.</span><span class="token function">beforeEach</span><span class="token punctuation">(</span><span class="token punctuation">(</span>to<span class="token punctuation">,</span> from<span class="token punctuation">,</span> next<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
  <span class="token keyword">const</span> authUser <span class="token operator">=</span> storeAuth<span class="token punctuation">.</span>value<span class="token punctuation">.</span>authUser<span class="token punctuation">;</span>
  <span class="token keyword">const</span> reqAuth <span class="token operator">=</span> to<span class="token punctuation">.</span>matched<span class="token punctuation">.</span><span class="token function">some</span><span class="token punctuation">(</span><span class="token punctuation">(</span>record<span class="token punctuation">)</span> <span class="token operator">=&gt;</span> record<span class="token punctuation">.</span>meta<span class="token punctuation">.</span>requiresAuth<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token keyword">const</span> loginQuery <span class="token operator">=</span> <span class="token punctuation">{</span> path<span class="token operator">:</span> <span class="token string">&quot;/login&quot;</span><span class="token punctuation">,</span> query<span class="token operator">:</span> <span class="token punctuation">{</span> redirect<span class="token operator">:</span> to<span class="token punctuation">.</span>fullPath <span class="token punctuation">}</span> <span class="token punctuation">}</span><span class="token punctuation">;</span>

  <span class="token keyword">if</span> <span class="token punctuation">(</span>reqAuth <span class="token operator">&amp;&amp;</span> <span class="token operator">!</span>authUser<span class="token punctuation">)</span> <span class="token punctuation">{</span>
    storeAuth<span class="token punctuation">.</span>value<span class="token punctuation">.</span><span class="token function">getAuthUser</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
      <span class="token punctuation">(</span><span class="token operator">!</span>storeAuth<span class="token punctuation">.</span>value<span class="token punctuation">.</span>authUser<span class="token punctuation">)</span> 
        <span class="token operator">?</span> <span class="token function">next</span><span class="token punctuation">(</span>loginQuery<span class="token punctuation">)</span>
          <span class="token operator">:</span><span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
    <span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span>
    <span class="token function">next</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// make sure to always call next()!</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre></div><p>Algunos escenarios deben manejarse aqu\xED:</p><ol><li>Si hay un usuario autenticado en estado, la ruta permite cargar la p\xE1gina.</li><li>Si no hay un usuario autenticado en el estado, haga una llamada a la API de Laravel para verificar si hay un usuario autenticado que se vincule con la sesi\xF3n. Suponiendo que lo haya, la tienda se completar\xE1 con los detalles del usuario. El enrutador permite que la p\xE1gina se cargue.</li><li>Finalmente, si no hay una sesi\xF3n v\xE1lida, redirija a la p\xE1gina de inicio de sesi\xF3n.</li></ol><p>Actualizar el navegador enviar\xE1 una solicitud GET a la API para el usuario autenticado, almacenar\xE1 los detalles en el estado. Navegar por la aplicaci\xF3n utilizar\xE1 el estado <code>auth</code> para minimizar las solicitudes de API, manteniendo las cosas \xE1giles. Esto tambi\xE9n ayuda con la seguridad. Cada vez que se obtienen datos de la API, Laravel verifica la sesi\xF3n. Si la sesi\xF3n deja de ser v\xE1lida, se env\xEDa una respuesta <code>401</code> o <code>419</code> al SPA. Manejado a trav\xE9s de un interceptor Axios, desconectando al usuario.</p><div class="language-js"><pre><code>auth<span class="token punctuation">.</span>interceptors<span class="token punctuation">.</span>response<span class="token punctuation">.</span><span class="token function">use</span><span class="token punctuation">(</span>
  <span class="token punctuation">(</span><span class="token parameter">response</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span> <span class="token keyword">return</span> response<span class="token punctuation">;</span> <span class="token punctuation">}</span><span class="token punctuation">,</span>
  <span class="token punctuation">(</span><span class="token parameter">error</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>
    <span class="token keyword">const</span> storeAuth <span class="token operator">=</span> <span class="token function">useAuthStore</span><span class="token punctuation">(</span><span class="token punctuation">)</span>
    
    <span class="token keyword">if</span> <span class="token punctuation">(</span>error<span class="token punctuation">.</span>response
      <span class="token operator">&amp;&amp;</span> <span class="token punctuation">[</span><span class="token number">401</span><span class="token punctuation">,</span> <span class="token number">419</span><span class="token punctuation">]</span><span class="token punctuation">.</span><span class="token function">includes</span><span class="token punctuation">(</span>error<span class="token punctuation">.</span>response<span class="token punctuation">.</span>status<span class="token punctuation">)</span>    
      <span class="token operator">&amp;&amp;</span> storeAuth<span class="token punctuation">.</span>authUser 
      <span class="token operator">&amp;&amp;</span> <span class="token operator">!</span>storeAuth<span class="token punctuation">.</span>guest
    <span class="token punctuation">)</span> <span class="token punctuation">{</span> storeAuth<span class="token punctuation">.</span><span class="token function">logout</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token punctuation">}</span>
    
    <span class="token keyword">return</span> Promise<span class="token punctuation">.</span><span class="token function">reject</span><span class="token punctuation">(</span>error<span class="token punctuation">)</span><span class="token punctuation">;</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre></div>`,17),e=[p];function c(u,l,i,r,k,d){return a(),s("div",null,e)}var f=n(o,[["render",c]]);export{m as __pageData,f as default};
